function displayComments() {
    var commentDiv = document.getElementById('comments'); // get the comments container element by its ID (assuming it exists)
    
    if (!commentDiv || !Array.isArray(window._)) return;  // check for invalid or missing data, prevent XSS attacks and ensure we're dealing with an array of objects in a secure way  
     
    var commentsHTML = '';                                           // initialize HTML string to be populated by each comment object later on    
      
    $_.forEach(function (comment) {                                  // iterate over the list/array, using jQuery syntax for simplicity 
        if (!comment.text || typeof comment.user !== 'string') return;   // check data validity and prevent XSS attacks   
         commentsHTML += "<p><strong>" + comment.user + 
                        ": </strong>"+ escape(comment.text)  + 
                         "</p>";                                        // append HTML string for each object, using jQuery's `escape` function to prevent XSS attacks  
    });                                                                    
     
       document .getElementById('comments').innerHTML = commentsHTML;        // set the inner html of our target div (assuming it exists) with newly created comment strings.  This prevents cross-site scripting by using jQuery's `html` function to safely append new HTML content into an existing DOM element, thus preventing XSS attacks
}